// ============== PIEZAS TAB ==============

function MovePatternGrid({ pieceType }) {
  const N = 7, center = 3;
  const moves = [];
  const slide = (dr, dc, maxStep) => {
    for (let i = 1; i <= maxStep; i++) {
      const nr = center + dr*i, nc = center + dc*i;
      if (nr < 0 || nr >= N || nc < 0 || nc >= N) break;
      moves.push([nr, nc]);
    }
  };
  const jump = (dr, dc) => {
    const nr = center + dr, nc = center + dc;
    if (nr >= 0 && nr < N && nc >= 0 && nc < N) moves.push([nr, nc]);
  };
  switch(pieceType) {
    case 'monarca': DIR8.forEach(([dr,dc]) => jump(dr,dc)); break;
    case 'hechicera': DIR8.forEach(([dr,dc]) => slide(dr,dc,5)); break;
    case 'fortaleza': DIR4.forEach(([dr,dc]) => slide(dr,dc,N)); break;
    case 'druida':
      DIAG.forEach(([dr,dc]) => slide(dr,dc,4));
      DIR4.forEach(([dr,dc]) => jump(dr,dc));
      break;
    case 'jinete': JINETE_OFFSETS.forEach(([dr,dc]) => jump(dr,dc)); break;
    case 'caballero':
      KNIGHT_OFFSETS.forEach(([dr,dc]) => jump(dr,dc));
      DIR8.forEach(([dr,dc]) => jump(dr,dc));
      break;
    case 'infante':
      jump(-1, 0); jump(-1, -1); jump(-1, 1);
      break;
  }
  const moveSet = new Set(moves.map(([r,c]) => `${r},${c}`));
  const cell = 24;
  return (
    <div style={{
      display: 'inline-grid',
      gridTemplateColumns: `repeat(${N}, ${cell}px)`,
      gap: 1, background: COLORS.cardLight, padding: 4,
      borderRadius: 6, border: `1px solid ${COLORS.goldDeep}66`,
    }}>
      {Array.from({length: N}, (_, r) => Array.from({length: N}, (_, c) => {
        const isCenter = r === center && c === center;
        const isMove = moveSet.has(`${r},${c}`);
        const dark = (r+c) % 2 === 1;
        return (
          <div key={`${r}-${c}`} style={{
            width: cell, height: cell,
            background: dark ? '#6B4A2B' : '#D9CAA5',
            display: 'flex', alignItems: 'center', justifyContent: 'center', position: 'relative',
          }}>
            {isCenter && <PieceImage piece={{type: pieceType, color: 'gold'}} size={cell-4} />}
            {isMove && !isCenter && (
              <div style={{
                width: 8, height: 8, borderRadius: '50%',
                background: COLORS.tileHL, boxShadow: `0 0 4px ${COLORS.tileHL}`,
              }}/>
            )}
          </div>
        );
      }))}
    </div>
  );
}

