// === Formato de reloj para los temporalizadores ===
// < 1 h  -> mm:ss   ;   >= 1 h -> h:mm:ss
function formatClock(ms) {
  const totalSec = Math.max(0, Math.floor((ms || 0) / 1000));
  const h = Math.floor(totalSec / 3600);
  const m = Math.floor((totalSec % 3600) / 60);
  const s = totalSec % 60;
  const pad = (n) => String(n).padStart(2, '0');
  return h > 0 ? `${h}:${pad(m)}:${pad(s)}` : `${pad(m)}:${pad(s)}`;
}

function JugarTab({ multiplayer = null }) {
  // === MULTIPLAYER CONTEXT ===
  const myColor = multiplayer ? multiplayer.game.color : 'gold';
  const oppColor = myColor === 'gold' ? 'crimson' : 'gold';
  const isLocalTurn = (color) => color === myColor;

  // === VISTA: tablero volteado para el jugador Carmesí en multiplayer ===
  // Esto sólo cambia el RENDER. Coordenadas lógicas (board, pieces, moves, red, IA) intactas.
  // Así cada jugador ve sus piezas siempre abajo (estilo Clash Royale).
  const flipped = !!multiplayer && myColor === 'crimson';
  const flipR = (r) => flipped ? (BOARD_SIZE - 1 - r) : r;
  const flipC = (c) => flipped ? (BOARD_SIZE - 1 - c) : c;

  const [pieces, setPieces] = useState(createInitialPieces);
  const [turn, setTurn] = useState('gold');
  const [selectedId, setSelectedId] = useState(null);
  const [highlights, setHighlights] = useState([]);
  const [abilityTargets, setAbilityTargets] = useState([]);
  const [activeAbility, setActiveAbility] = useState(null);
  const [cooldowns, setCooldowns] = useState({ gold: {}, crimson: {} });
  const [oncePerGame, setOncePerGame] = useState({
    gold: { monarca: false, infante: false },
    crimson: { monarca: false, infante: false },
  });
  const [pendingJinete, setPendingJinete] = useState(null);
  const [promotionPick, setPromotionPick] = useState(null);
  const [winner, setWinner] = useState(null);
  const [log, setLog] = useState([]);
  const [captured, setCaptured] = useState({ gold: [], crimson: [] });
  const [aiThinking, setAiThinking] = useState(false);
  const [animating, setAnimating] = useState(false);
  const [difficulty, setDifficulty] = useState('normal');
  const [scenario, setScenario] = useState('clasico');
  const [cellSize, setCellSize] = useState(40);
  const [turnNumber, setTurnNumber] = useState(0);
  const [sfxOn, setSfxOn] = useState(soundConfig.effects);
  const [ambientOn, setAmbientOn] = useState(soundConfig.ambient);

  // === TEMPORALIZADORES (task: reloj por jugador + reloj total) ===
  // - Cada color tiene su reloj, que corre SOLO durante su turno y se frena
  //   cuando le toca al rival. Se maneja por completo a partir del estado `turn`
  //   y `winner`, así funciona idéntico en IA y en online (donde el turno lo
  //   manda el servidor).
  // - El reloj TOTAL arranca al empezar la partida y no se detiene hasta que hay
  //   ganador; muestra cuánto duró la partida en total.
  const [clockDisplay, setClockDisplay] = useState({ gold: 0, crimson: 0, total: 0 });
  const clockAccumRef = useRef({ gold: 0, crimson: 0 }); // ms acumulados de turnos ya cerrados
  const clockActiveRef = useRef(null);                   // color del segmento abierto
  const clockSegStartRef = useRef(null);                 // timestamp de inicio del segmento
  const clockTotalStartRef = useRef(null);               // timestamp de inicio del total
  const clockTotalFinalRef = useRef(null);               // total congelado al terminar
  const clockRunningRef = useRef(false);                 // ¿algún reloj corriendo?

  // === Inicio de partida + animación "¡A LAS ARMAS!" ===
  // La partida (y los relojes) NO arranca sola: contra la IA hay un botón
  // "COMENZAR PARTIDA"; online arranca al conectar, pero siempre con un cartel
  // de inicio estilo juego de pelea para avisar que empezó.
  const [started, setStarted] = useState(false);
  const startedRef = useRef(false);
  const [goAnim, setGoAnim] = useState(false);
  const goTimerRef = useRef(null);

  function triggerGo() {
    setGoAnim(true);
    if (goTimerRef.current) clearTimeout(goTimerRef.current);
    goTimerRef.current = setTimeout(() => setGoAnim(false), 1500);
  }

  function startMatch() {
    if (startedRef.current) return;
    startedRef.current = true;
    setStarted(true);     // dispara el efecto de relojes (abre el 1er segmento)
    ensureAudio();        // desbloquea/recalienta el audio dentro del gesto
    triggerGo();
  }

  function clockSnapshot() {
    const now = Date.now();
    const acc = clockAccumRef.current;
    const g = acc.gold + (clockActiveRef.current === 'gold' && clockSegStartRef.current != null ? now - clockSegStartRef.current : 0);
    const c = acc.crimson + (clockActiveRef.current === 'crimson' && clockSegStartRef.current != null ? now - clockSegStartRef.current : 0);
    const total = clockTotalFinalRef.current != null
      ? clockTotalFinalRef.current
      : (clockTotalStartRef.current != null ? now - clockTotalStartRef.current : 0);
    return { gold: g, crimson: c, total };
  }

  // Deja los relojes en CERO y "sin arrancar". Arrancan recién con startMatch().
  function resetClocks() {
    clockAccumRef.current = { gold: 0, crimson: 0 };
    clockTotalFinalRef.current = null;
    clockTotalStartRef.current = null;
    clockActiveRef.current = null;
    clockSegStartRef.current = null;
    clockRunningRef.current = false;
    setClockDisplay({ gold: 0, crimson: 0, total: 0 });
  }

  // Iniciar/parar música ambiente cuando cambia el toggle
  useEffect(() => {
    setAmbient(ambientOn);
  }, [ambientOn]);
  useEffect(() => {
    setEffects(sfxOn);
  }, [sfxOn]);

  const piecesRef = useRef(pieces);
  const cooldownsRef = useRef(cooldowns);
  const oncePerGameRef = useRef(oncePerGame);
  const turnNumberRef = useRef(turnNumber);
  const turnRef = useRef(turn);
  // Memoria de la IA: cuántas habilidades usó en la partida (para el tope por nivel).
  const aiAbilitiesUsedRef = useRef(0);
  // Dedup de acciones remotas (último _tn que cerró turno ya procesado).
  const lastRemoteTnRef = useRef(-1);
  useEffect(() => { piecesRef.current = pieces; }, [pieces]);
  useEffect(() => { cooldownsRef.current = cooldowns; }, [cooldowns]);
  useEffect(() => { oncePerGameRef.current = oncePerGame; }, [oncePerGame]);
  useEffect(() => { turnNumberRef.current = turnNumber; }, [turnNumber]);
  useEffect(() => { turnRef.current = turn; }, [turn]);

  // === v11: SINCRONIZACIÓN DE TURNO DESDE EL SERVIDOR (autoritativo) ===
  // En multiplayer, el servidor es el dueño del turno. Cada vez que cambia
  // serverTurn, alineamos el estado local (turn + turnNumber) con él.
  // Esto elimina por completo el bug de "jugar solo": ya no hay dos contadores
  // independientes que puedan divergir, hay UNO solo que vive en el servidor.
  const serverTurn = multiplayer ? multiplayer.serverTurn : null;
  useEffect(() => {
    if (!multiplayer || !serverTurn) return;
    if (typeof serverTurn.currentTurn === 'string') {
      setTurn(serverTurn.currentTurn);
      turnRef.current = serverTurn.currentTurn;
    }
    if (typeof serverTurn.turnNumber === 'number') {
      setTurnNumber(serverTurn.turnNumber);
      turnNumberRef.current = serverTurn.turnNumber;
    }
  }, [multiplayer, serverTurn]);

  // Mantener startedRef en sincronía con el estado.
  useEffect(() => { startedRef.current = started; }, [started]);

  // Online: la partida arranca al conectar. Lanzamos el inicio (cartel + relojes)
  // una sola vez al montar en modo multijugador.
  useEffect(() => {
    if (multiplayer && !startedRef.current) startMatch();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [multiplayer]);

  // === TEMPORALIZADORES: abrir/cerrar segmentos según `turn`, `winner` y `started` ===
  // Cada vez que cambia de quién es el turno, cerramos el segmento del color
  // anterior (sumando su tiempo) y abrimos el del nuevo. Al haber ganador,
  // congelamos todo (incluido el total). Si la partida no arrancó, no corre nada.
  useEffect(() => {
    const now = Date.now();
    if (winner) {
      // Cerrar el segmento activo y congelar el total.
      if (clockActiveRef.current && clockSegStartRef.current != null) {
        clockAccumRef.current[clockActiveRef.current] += now - clockSegStartRef.current;
      }
      clockActiveRef.current = null;
      clockSegStartRef.current = null;
      if (clockTotalFinalRef.current == null && clockTotalStartRef.current != null) {
        clockTotalFinalRef.current = now - clockTotalStartRef.current;
      }
      clockRunningRef.current = false;
      setClockDisplay(clockSnapshot());
      return;
    }
    if (!started) {
      // Todavía no se apretó "Comenzar partida": relojes en 0, sin correr.
      clockRunningRef.current = false;
      return;
    }
    // Partida en curso: asegurar que el total esté corriendo.
    if (clockTotalStartRef.current == null) clockTotalStartRef.current = now;
    clockTotalFinalRef.current = null;
    clockRunningRef.current = true;
    // Cambió el color activo → cerrar el anterior y abrir el nuevo.
    if (clockActiveRef.current !== turn) {
      if (clockActiveRef.current && clockSegStartRef.current != null) {
        clockAccumRef.current[clockActiveRef.current] += now - clockSegStartRef.current;
      }
      clockActiveRef.current = turn;
      clockSegStartRef.current = now;
    }
    setClockDisplay(clockSnapshot());
  }, [turn, winner, started]);

  // Tick de pantalla: refresca los relojes 4 veces por segundo mientras corren.
  useEffect(() => {
    const id = setInterval(() => {
      if (clockRunningRef.current) setClockDisplay(clockSnapshot());
    }, 250);
    return () => clearInterval(id);
  }, []);

  // === AUDIO: pausar/reanudar al minimizar la app ===
  // Evita que el reverb del ambient siga colgado distorsionado en background,
  // y que sonidos del juego suenen mal al volver.
  useEffect(() => {
    function onVisibilityChange() {
      try {
        if (!Tone || !Tone.context) return;
        if (document.visibilityState === 'hidden') {
          Tone.context.suspend();
        } else if (document.visibilityState === 'visible') {
          Tone.context.resume();
        }
      } catch (_) {}
    }
    document.addEventListener('visibilitychange', onVisibilityChange);
    return () => document.removeEventListener('visibilitychange', onVisibilityChange);
  }, []);

  // === MULTIPLAYER: envío y recepción de acciones ===
  // Modelo nuevo (sin candado por tiempo):
  //  - sendIfLocal solo envía cuando es MI turno (turnRef === myColor).
  //    Esto evita reenviar acciones que llegaron del rival (durante su turno).
  //  - Cada mensaje lleva un sello "_tn" (número de turno). El receptor descarta
  //    mensajes cuyo _tn no coincide con su turnNumber actual (duplicados,
  //    fuera de orden, o desincronizados — ej. tras minimizar la app).
  // === MULTIPLAYER v11: envío de acciones al SERVIDOR ===
  // Ya no llevamos sello de turno local; el servidor sella _tn y valida el turno.
  // sendIfLocal solo envía cuando es MI turno (defensa local), pero la autoridad
  // real la tiene el servidor: si llegara fuera de turno, lo rebota con
  // 'action_rejected' y nos resincroniza.
  //   turnEnds: por defecto true. Solo el 1er movimiento de Doble Galope pasa
  //   turnEnds:false (no termina el turno, viene un 2° galope).
  function sendIfLocal(action, turnEnds = true) {
    if (!multiplayer) return;
    if (turnRef.current !== myColor) return;
    try {
      // ANTI-DESYNC: adjuntamos SIEMPRE el tablero completo resultante (verdad
      // absoluta del que mueve). El rival lo copia exacto, así nunca quedan
      // piezas encimadas/congeladas por reconstrucción independiente.
      multiplayer.sendAction({ ...action, turnEnds, pieces: piecesSnapshot() });
    } catch (_) {}
  }

  // Foto mínima del tablero para sincronizar al rival (verdad absoluta).
  function piecesSnapshot() {
    return piecesRef.current.map(p => ({
      id: p.id, type: p.type, color: p.color,
      row: p.row, col: p.col, captured: !!p.captured,
      createdAtTurn: p.createdAtTurn || 0,
    }));
  }

  const board = useMemo(() => computeBoard(pieces), [pieces]);
  const sc = SCENARIOS[scenario];

  useEffect(() => {
    function updateSize() {
      const w = Math.min(window.innerWidth - 32, 420);
      setCellSize(Math.floor(w / BOARD_SIZE));
    }
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  function reset() {
    setPieces(createInitialPieces());
    setTurn('gold'); setSelectedId(null); setHighlights([]); setAbilityTargets([]);
    setActiveAbility(null); setCooldowns({ gold: {}, crimson: {} });
    setOncePerGame({ gold: {monarca:false,infante:false}, crimson: {monarca:false,infante:false} });
    setPendingJinete(null); setPromotionPick(null); setWinner(null);
    setLog([]); setCaptured({ gold: [], crimson: [] }); setAiThinking(false);
    setAnimating(false);
    setTurnNumber(0);
    aiAbilitiesUsedRef.current = 0;
    lastRemoteTnRef.current = -1;
    resetClocks();
    // Volver al estado "sin empezar": contra la IA reaparece el botón Comenzar.
    // Online se vuelve a iniciar solo (efecto de multiplayer), con su cartel.
    setGoAnim(false);
    if (multiplayer) { startedRef.current = false; setStarted(false); startMatch(); }
    else { startedRef.current = false; setStarted(false); }
  }

  const selectedPiece = selectedId ? pieces.find(p => p.id === selectedId && !p.captured) : null;
  const logEntry = (msg) => setLog(prev => [...prev, msg].slice(-30));

  function decrementCooldowns(color) {
    setCooldowns(prev => {
      const cd = { ...prev[color] };
      for (const k of Object.keys(cd)) {
        cd[k] = Math.max(0, cd[k]-1);
        if (cd[k] === 0) delete cd[k];
      }
      return { ...prev, [color]: cd };
    });
  }

  function checkWinAfterMove(newPieces) {
    const hasGold = newPieces.some(p => !p.captured && p.type === 'monarca' && p.color === 'gold');
    const hasCrim = newPieces.some(p => !p.captured && p.type === 'monarca' && p.color === 'crimson');
    if (!hasCrim) return 'gold';
    if (!hasGold) return 'crimson';
    return null;
  }

  function endTurn(justMovedColor) {
    decrementCooldowns(justMovedColor);
    setActiveAbility(null);
    // v11: en MULTIPLAYER el servidor es el dueño del turno. NO avanzamos el
    // turno ni el turnNumber localmente — llegará vía 'turn_state' y el efecto
    // de sincronización lo aplicará. Avanzarlo acá causaría doble-conteo y la
    // vieja divergencia. En modo IA (sin multiplayer) sí avanzamos local.
    if (multiplayer) return;
    const nextTurn = justMovedColor === 'gold' ? 'crimson' : 'gold';
    setTurnNumber(prev => prev + 1);
    setTurn(nextTurn);
    turnRef.current = nextTurn;
    turnNumberRef.current = (turnNumberRef.current || 0) + 1;
  }

  function executeMove(pieceId, toRow, toCol, isAbility = false, abilityLabel = null) {
    ensureAudio();
    const piece = piecesRef.current.find(p => p.id === pieceId);
    if (!piece || piece.captured) return;
    const target = piecesRef.current.find(p => !p.captured && p.row === toRow && p.col === toCol);

    // Multiplayer: metadatos para el rival (el envío real va MÁS ABAJO, después
    // de actualizar el tablero local, para que la foto sincronizada sea correcta).
    let galopePhase = null;
    if (abilityLabel === 'Doble Galope (1°)') galopePhase = 'first';
    else if (abilityLabel === 'Doble Galope (2°)') galopePhase = 'second';
    // El 1er movimiento de Doble Galope NO termina el turno (viene un 2°).
    const movEndsTurn = galopePhase !== 'first';

    if (isAbility && abilityLabel) {
      // Ability-based move (Embestida, Salto Real)
      playAbility(piece.type);
    } else {
      playMoveSound(piece.type);
    }

    setAnimating(true);
    setSelectedId(null); setHighlights([]); setAbilityTargets([]);

    let promotedTo = null;
    const newPieces = piecesRef.current.map(p => {
      if (p.id === pieceId) {
        let newType = p.type;
        let newCreatedAtTurn = p.createdAtTurn;
        if (p.type === 'infante' && ((p.color === 'gold' && toRow === 0) || (p.color === 'crimson' && toRow === BOARD_SIZE-1))) {
          newType = 'hechicera';
          promotedTo = 'hechicera';
          newCreatedAtTurn = turnNumberRef.current;
        }
        return { ...p, row: toRow, col: toCol, type: newType, createdAtTurn: newCreatedAtTurn };
      }
      if (target && p.id === target.id) {
        return { ...p, captured: true };
      }
      return p;
    });
    setPieces(newPieces);
    piecesRef.current = newPieces;

    // Ahora SÍ enviamos al rival, con la foto del tablero ya actualizado.
    sendIfLocal({
      kind: 'move',
      pieceId, toRow, toCol,
      isAbility: !!isAbility,
      abilityLabel: abilityLabel || null,
      galopePhase,
    }, movEndsTurn);

    const coord = `${String.fromCharCode(97+toCol)}${BOARD_SIZE-toRow}`;
    let entry = (piece.color === 'gold' ? '🟡 ' : '🔴 ');
    if (abilityLabel) entry += `⚜ ${abilityLabel} → ${coord}`;
    else entry += `${PIECE_DATA[piece.type].name} → ${coord}`;
    if (target) entry += ` ✕ ${PIECE_DATA[target.type].name}`;
    if (promotedTo) entry += ` 👑→Hechicera`;
    logEntry(entry);

    const isKingCapture = target && target.type === 'monarca';

    if (target) {
      setCaptured(prev => ({
        ...prev,
        [piece.color === 'gold' ? 'crimson' : 'gold']:
          [...prev[piece.color === 'gold' ? 'crimson' : 'gold'], target.type]
      }));
      if (isKingCapture) {
        setTimeout(() => playKingCapture(), 220);
      } else {
        setTimeout(() => playRegularCapture(), 280);
      }
    }

    setTimeout(() => {
      setAnimating(false);
      const w = checkWinAfterMove(newPieces);
      if (w) {
        setWinner(w);
        // Victory/defeat plays AFTER the king capture sound finishes
        setTimeout(() => {
          if (w === myColor) playVictory(); else playDefeat();
        }, isKingCapture ? 1500 : 200);
        return;
      }
      // Pending Jinete (after first move of doble galope)
      // FIX desync multiplayer del 2° galope:
      // Antes leíamos el state `pendingJinete` dentro de este setTimeout, pero el
      // closure se queda con el valor del render donde se programó el timer.
      // En el lado del rival, applyRemoteAction hace setPendingJinete({phase:'first'})
      // y JUSTO DESPUÉS llama executeMove en el mismo handler — sin re-render entre
      // medio. Entonces el closure veía pendingJinete = null, no entraba al if, y
      // ejecutaba endTurn(piece.color) automáticamente terminando el turno antes
      // de tiempo. Como el rival ya había "pasado" el turno, cuando llegaba el 2°
      // movimiento la validación anti-desync lo descartaba con "no es turno del rival".
      // Solución: detectar el galope por `abilityLabel` (parámetro local de
      // executeMove, siempre actualizado) en vez del state stale. Y preservar
      // `aiMode` usando el callback form de setState.
      if (abilityLabel === 'Doble Galope (1°)') {
        const newBoard = computeBoard(newPieces);
        const nextMoves = getRawMoves(newBoard, toRow, toCol);
        if (nextMoves.length > 0) {
          setPendingJinete(prev => ({
            pieceId,
            phase: 'second',
            ...(prev && prev.aiMode ? { aiMode: true } : {})
          }));
          // Solo mostrar highlights al jugador que controla la pieza
          // (en online, el rival no debe ver highlights sobre la pieza enemiga)
          if (piece.color === myColor) {
            setSelectedId(pieceId);
            setHighlights(nextMoves);
          }
          return;
        }
      }
      setPendingJinete(null);
      endTurn(piece.color);
    }, ANIM_MS);
  }

  // === AI execution helpers ===

  function aiCaptureWithoutMoving(pieceId, target, abilityLabel, cooldownKey, cooldownVal) {
    const piece = piecesRef.current.find(p => p.id === pieceId);
    if (!piece) return;
    playAbility(piece.type);

    setAnimating(true);
    const newPieces = piecesRef.current.map(p => {
      if (target && p.id === target.id) return { ...p, captured: true };
      return p;
    });
    setPieces(newPieces); piecesRef.current = newPieces;
    setCaptured(prev => ({ ...prev, gold: [...prev.gold, target.type] }));
    if (cooldownKey) {
      setCooldowns(prev => ({ ...prev, crimson: { ...prev.crimson, [cooldownKey]: cooldownVal }}));
    }
    const coord = `${String.fromCharCode(97+target.col)}${BOARD_SIZE-target.row}`;
    logEntry(`🔴 ⚜ ${abilityLabel} ✕ ${PIECE_DATA[target.type].name} en ${coord}`);

    const isKingCapture = target.type === 'monarca';
    if (isKingCapture) {
      setTimeout(() => playKingCapture(), 250);
    } else {
      setTimeout(() => playRegularCapture(), 280);
    }

    setTimeout(() => {
      setAnimating(false);
      const w = checkWinAfterMove(newPieces);
      if (w) {
        setWinner(w);
        setTimeout(() => {
          if (w === myColor) playVictory(); else playDefeat();
        }, isKingCapture ? 1500 : 200);
        return;
      }
      endTurn('crimson');
    }, ANIM_MS);
  }

  function aiSpawnInfante(target) {
    playAbility('druida');
    const newId = `spawn-crimson-${pieceIdCounter++}`;
    const newPieces = [...piecesRef.current, {
      id: newId, type: 'infante', color: 'crimson', row: target[0], col: target[1], captured: false,
      createdAtTurn: turnNumberRef.current
    }];
    setPieces(newPieces); piecesRef.current = newPieces;
    setCooldowns(prev => ({ ...prev, crimson: { ...prev.crimson, druida: 9 }}));
    const coord = `${String.fromCharCode(97+target[1])}${BOARD_SIZE-target[0]}`;
    logEntry(`🔴 ⚜ Brote → Infante en ${coord}`);
    setAnimating(true);
    setTimeout(() => {
      setAnimating(false);
      endTurn('crimson');
    }, 600);
  }

  function aiCoronacion(pieceId, newType) {
    playAbility('infante');
    const newPieces = piecesRef.current.map(p =>
      p.id === pieceId ? { ...p, type: newType, createdAtTurn: turnNumberRef.current } : p
    );
    setPieces(newPieces); piecesRef.current = newPieces;
    setOncePerGame(prev => ({ ...prev, crimson: { ...prev.crimson, infante: true }}));
    logEntry(`🔴 ⚜ Coronación → ${PIECE_DATA[newType].name}`);
    setAnimating(true);
    setTimeout(() => {
      setAnimating(false);
      endTurn('crimson');
    }, 900);
  }

  // === AI TURN ===
  const isAiTurn = !multiplayer && started && turn === 'crimson' && !winner && !animating && !promotionPick;
  useEffect(() => {
    if (!isAiTurn) return;
    setAiThinking(true);
    const handle = setTimeout(() => {
      const curBoard = computeBoard(piecesRef.current);
      const cfg = DIFFICULTY_LEVELS[difficulty];
      const cds = cooldownsRef.current;

      // Opciones de evaluación + memoria de cooldowns de AMBOS colores.
      // (La IA es crimson; gold es el rival.)
      const opts = {
        positional: !!cfg.positional, threatEval: !!cfg.threatEval,
        mobility: !!cfg.mobility, kingSafety: !!cfg.kingSafety,
        centerControl: !!cfg.centerControl, abilityThreat: !!cfg.abilityThreat,
        quiescence: !!cfg.quiescence, qdepth: cfg.qdepth || 4, advanced: !!cfg.advanced,
        myCooldowns: cds.crimson || {}, enemyCooldowns: cds.gold || {},
      };

      // 1. Mejor movimiento normal (búsqueda principal).
      const regResult = aiChooseRegularMove(curBoard, 'crimson', cfg, opts);
      const regularMove = regResult ? regResult.move : null;
      const regularScore = regResult ? regResult.score : -Infinity;

      // 2. Habilidad candidata (respetando el tope de habilidades del nivel).
      const maxAb = (cfg.maxAbilities === undefined) ? Infinity : cfg.maxAbilities;
      const abilitiesAllowed = cfg.abilities !== 'none' && aiAbilitiesUsedRef.current < maxAb;
      const abilityMove = abilitiesAllowed
        ? findAIAbility(curBoard, 'crimson', cds, oncePerGameRef.current, difficulty, turnNumberRef.current)
        : null;

      setAiThinking(false);

      let regularCaptureValue = 0;
      if (regularMove && curBoard[regularMove.to[0]][regularMove.to[1]]) {
        regularCaptureValue = PIECE_DATA[curBoard[regularMove.to[0]][regularMove.to[1]].type].value;
      }

      // ¿Habilidad o movimiento normal?
      let useAbility = false;
      if (abilityMove) {
        if (cfg.advanced) {
          // Simular el tablero resultante de la habilidad.
          let simBoard = curBoard.map(row => row.slice());
          if (abilityMove.abilityType === 'fortaleza' || abilityMove.abilityType === 'hechicera') {
            simBoard[abilityMove.target[0]][abilityMove.target[1]] = null; // captura sin moverse
          } else if (abilityMove.abilityType === 'caballero' || abilityMove.abilityType === 'monarca' || abilityMove.abilityType === 'jinete') {
            simBoard = applyMoveSim(curBoard, abilityMove.from, abilityMove.target);
          } else if (abilityMove.abilityType === 'druida') {
            simBoard[abilityMove.target[0]][abilityMove.target[1]] = {
              type: 'infante', color: 'crimson', row: abilityMove.target[0], col: abilityMove.target[1]
            };
          } else if (abilityMove.abilityType === 'infante') {
            const inf = simBoard[abilityMove.from[0]][abilityMove.from[1]];
            if (inf) simBoard[abilityMove.from[0]][abilityMove.from[1]] = { ...inf, type: abilityMove.newType || 'caballero' };
          }
          // Evaluar la habilidad CONTANDO la respuesta del rival (mini-búsqueda),
          // así no usa una habilidad que termina perdiendo material al turno siguiente.
          let abilityScore;
          try {
            const respDepth = difficulty === 'invencible' ? 2 : 1;
            abilityScore = minimax(simBoard, respDepth, -Infinity, Infinity, 'crimson', 'gold', opts, Date.now() + 250).score;
          } catch (e) {
            abilityScore = evalBoard(simBoard, 'crimson', opts);
          }
          useAbility = abilityScore > regularScore + 0.25;
          // Habilidad defensiva del Monarca: si está bajo amenaza, siempre escapar.
          if (abilityMove.abilityType === 'monarca' && abilityMove.score >= 100) useAbility = true;
        } else {
          useAbility = (abilityMove.score > regularCaptureValue) || abilityMove.abilityType === 'monarca';
        }
      }

      if (useAbility) {
        executeAIAbility(abilityMove);
      } else if (regularMove) {
        executeMove(regularMove.pieceId, regularMove.to[0], regularMove.to[1]);
      } else {
        // Sin jugadas legales
        setWinner('gold');
        playVictory();
      }
    }, 150);
    return () => clearTimeout(handle);
  }, [isAiTurn, difficulty]);

  function executeAIAbility(abilityMove) {
    const { abilityType, pieceId, target, newType } = abilityMove;
    const piece = piecesRef.current.find(p => p.id === pieceId);
    if (!piece) return;
    aiAbilitiesUsedRef.current += 1; // memoria: la IA registra cada habilidad usada

    if (abilityType === 'fortaleza') {
      const targetPiece = piecesRef.current.find(p => !p.captured && p.row === target[0] && p.col === target[1]);
      if (!targetPiece) return;
      aiCaptureWithoutMoving(pieceId, targetPiece, 'Aplastar', 'fortaleza', 6);
    } else if (abilityType === 'hechicera') {
      const targetPiece = piecesRef.current.find(p => !p.captured && p.row === target[0] && p.col === target[1]);
      if (!targetPiece) return;
      aiCaptureWithoutMoving(pieceId, targetPiece, 'Hechizo Letal', 'hechicera', 7);
    } else if (abilityType === 'caballero') {
      setCooldowns(prev => ({ ...prev, crimson: { ...prev.crimson, caballero: 6 }}));
      executeMove(pieceId, target[0], target[1], true, 'Embestida');
    } else if (abilityType === 'monarca') {
      setOncePerGame(prev => ({ ...prev, crimson: { ...prev.crimson, monarca: true }}));
      executeMove(pieceId, target[0], target[1], true, 'Salto Real');
    } else if (abilityType === 'druida') {
      aiSpawnInfante(target);
    } else if (abilityType === 'infante') {
      aiCoronacion(pieceId, newType || 'caballero');
    } else if (abilityType === 'jinete') {
      // Doble Galope: execute first move; second move handled by pending state
      setCooldowns(prev => ({ ...prev, crimson: { ...prev.crimson, jinete: 9 }}));
      setPendingJinete({ pieceId, phase: 'first', aiMode: true });
      executeMove(pieceId, target[0], target[1], true, 'Doble Galope (1°)');
    }
  }

  // Handle AI's second Jinete move (Doble Galope)
  useEffect(() => {
    if (!pendingJinete || !pendingJinete.aiMode || pendingJinete.phase !== 'second') return;
    if (animating) return;
    const timer = setTimeout(() => {
      const piece = piecesRef.current.find(p => p.id === pendingJinete.pieceId && !p.captured);
      if (!piece) { setPendingJinete(null); return; }
      const curBoard = computeBoard(piecesRef.current);
      const moves = getRawMoves(curBoard, piece.row, piece.col);
      if (moves.length === 0) {
        setPendingJinete(null);
        endTurn('crimson');
        return;
      }
      // Pick best move (prefer captures)
      moves.sort((a, b) => {
        const av = curBoard[a[0]][a[1]] ? PIECE_DATA[curBoard[a[0]][a[1]].type].value : 0;
        const bv = curBoard[b[0]][b[1]] ? PIECE_DATA[curBoard[b[0]][b[1]].type].value : 0;
        return bv - av;
      });
      const [tr, tc] = moves[0];
      setPendingJinete(null);
      executeMove(piece.id, tr, tc, true, 'Doble Galope (2°)');
    }, 600);
    return () => clearTimeout(timer);
  }, [pendingJinete, animating]);

  // === PLAYER CLICK HANDLERS ===

  // Limpia TODO el estado de selección/habilidad. Se usa cada vez que el jugador
  // se "arrepiente" (toca otra pieza, toca fuera, etc.). v11 FIX: antes, al tocar
  // otra pieza mientras el Jinete tenía Doble Galope activado (o cualquier
  // habilidad en proceso de targeting), quedaban activeAbility/pendingJinete
  // colgados. Esos estados zombis hacían que la siguiente habilidad pareciera
  // "ya usada / desactivada". Ahora se limpian siempre.
  function clearSelectionAndAbility() {
    setSelectedId(null);
    setHighlights([]);
    setActiveAbility(null);
    setAbilityTargets([]);
    setPendingJinete(null);
  }

  function onSquareClick(r, c) {
    ensureAudio();
    if (!started) return; // la partida todavía no arrancó (falta apretar "Comenzar")
    if (winner || turn !== myColor || aiThinking || animating || promotionPick) return;

    if (pendingJinete && pendingJinete.phase === 'second' && !pendingJinete.aiMode) {
      const isMove = highlights.some(([nr,nc]) => nr===r && nc===c);
      if (isMove) {
        executeMove(pendingJinete.pieceId, r, c, true, 'Doble Galope (2°)');
        return;
      }
      setPendingJinete(null);
      logEntry(`${myColor === 'gold' ? '🟡' : '🔴'} Jinete pasa su 2° galope`);
      setSelectedId(null); setHighlights([]);
      sendIfLocal({ kind: 'galope_pass' });
      endTurn(myColor);
      return;
    }

    if (activeAbility && abilityTargets.length > 0) {
      const isTarget = abilityTargets.some(([tr,tc]) => tr===r && tc===c);
      if (isTarget) {
        executePlayerAbility(r, c);
        return;
      }
      // Se arrepintió de la habilidad de targeting: limpiar TODO.
      clearSelectionAndAbility();
      return;
    }

    const piece = board[r][c];

    // CASO ESPECIAL: Doble Galope activado en fase 'first' (esperando el 1er
    // movimiento). El estado vive en activeAbility==='jinete' + pendingJinete.
    // Si toca una casilla de movimiento válida → ejecuta el 1er galope.
    // Si toca CUALQUIER OTRA cosa (otra pieza, casilla vacía, la misma pieza) →
    // cancela el Doble Galope limpiando el estado (FIX del bug "se arrepintió").
    if (activeAbility === 'jinete' && pendingJinete && pendingJinete.phase === 'first') {
      const isMove = highlights.some(([nr,nc]) => nr===r && nc===c);
      if (isMove) {
        const sel = pieces.find(p => p.id === selectedId);
        if (sel) {
          setCooldowns(prev => ({ ...prev, [myColor]: { ...prev[myColor], jinete: 9 }}));
          executeMove(sel.id, r, c, true, 'Doble Galope (1°)');
        }
        return;
      }
      // Cancelar el Doble Galope. Si tocó otra pieza propia, la seleccionamos.
      clearSelectionAndAbility();
      if (piece && piece.color === myColor) {
        setSelectedId(piece.id);
        setHighlights(getRawMoves(board, r, c));
        playSelect();
      }
      return;
    }

    if (selectedId) {
      const sel = pieces.find(p => p.id === selectedId);
      if (!sel) { clearSelectionAndAbility(); return; }
      if (sel.row === r && sel.col === c) {
        // Tocó la misma pieza: deseleccionar y limpiar cualquier habilidad pendiente.
        clearSelectionAndAbility();
        return;
      }
      const isMove = highlights.some(([nr,nc]) => nr===r && nc===c);
      if (isMove) {
        executeMove(sel.id, r, c);
        return;
      }
      if (piece && piece.color === myColor) {
        // Cambió de pieza: limpiar habilidad pendiente antes de seleccionar la nueva.
        setActiveAbility(null);
        setAbilityTargets([]);
        setPendingJinete(null);
        setSelectedId(piece.id);
        setHighlights(getRawMoves(board, r, c));
        playSelect();
        return;
      }
      clearSelectionAndAbility();
      return;
    }

    if (piece && piece.color === myColor) {
      setSelectedId(piece.id);
      setHighlights(getRawMoves(board, r, c));
      playSelect();
    }
  }

  function abilityAvailable(pieceType) {
    if (pieceType === 'monarca' || pieceType === 'infante') {
      return !oncePerGame[myColor][pieceType];
    }
    return !cooldowns[myColor][pieceType];
  }

  function activateAbility() {
    if (!selectedPiece) return;
    const piece = selectedPiece;
    const type = piece.type;
    if (!abilityAvailable(type)) return;
    const [r, c] = [piece.row, piece.col];

    if (type === 'monarca') {
      const targets = [];
      for (const [dr,dc] of DIR4) {
        const nr = r+dr*2, nc = c+dc*2;
        if (inBounds(nr,nc)) {
          const tgt = board[nr][nc];
          // FIX: usar myColor (no 'gold' hardcodeado) para no bloquear al jugador Carmesí
          if (!tgt || tgt.color !== myColor) targets.push([nr,nc]);
        }
      }
      if (targets.length === 0) return;
      setActiveAbility('monarca'); setAbilityTargets(targets); setHighlights([]);
    } else if (type === 'hechicera') {
      const targets = [];
      for (let dr=-3; dr<=3; dr++) for (let dc=-3; dc<=3; dc++) {
        if (dr===0 && dc===0) continue;
        const nr = r+dr, nc = c+dc;
        // FIX: apuntar a piezas del oponente (oppColor), no a 'crimson' fijo
        // NERF: el Hechizo Letal NO puede capturar al Monarca enemigo.
        // Al Monarca solo se lo puede comer con vía libre (movimiento normal).
        if (inBounds(nr,nc) && board[nr][nc] && board[nr][nc].color === oppColor
            && board[nr][nc].type !== 'monarca') {
          targets.push([nr,nc]);
        }
      }
      if (targets.length === 0) return;
      setActiveAbility('hechicera'); setAbilityTargets(targets); setHighlights([]);
    } else if (type === 'fortaleza') {
      const targets = [];
      for (const [dr,dc] of DIR8) {
        const nr = r+dr, nc = c+dc;
        // FIX: apuntar a piezas del oponente (oppColor), no a 'crimson' fijo
        if (inBounds(nr,nc) && board[nr][nc] && board[nr][nc].color === oppColor) {
          targets.push([nr,nc]);
        }
      }
      if (targets.length === 0) return;
      setActiveAbility('fortaleza'); setAbilityTargets(targets); setHighlights([]);
    } else if (type === 'druida') {
      const targets = [];
      for (const [dr,dc] of DIR8) {
        const nr = r+dr, nc = c+dc;
        if (inBounds(nr,nc) && !board[nr][nc]) targets.push([nr,nc]);
      }
      if (targets.length === 0) return;
      setActiveAbility('druida'); setAbilityTargets(targets); setHighlights([]);
    } else if (type === 'caballero') {
      const targets = [];
      for (const [dr,dc] of DIR8) {
        for (let i=1; i<=4; i++) {
          const nr = r+dr*i, nc = c+dc*i;
          if (!inBounds(nr,nc)) break;
          if (board[nr][nc]) {
            // FIX: usar myColor (no 'gold' hardcodeado) para no bloquear al jugador Carmesí
            if (board[nr][nc].color !== myColor) targets.push([nr,nc]);
            break;
          }
          targets.push([nr,nc]);
        }
      }
      if (targets.length === 0) return;
      setActiveAbility('caballero'); setAbilityTargets(targets); setHighlights([]);
    } else if (type === 'jinete') {
      // Solución A: bloquear Doble Galope si la pieza fue creada/promocionada hace menos de 2 turnos
      if (turnNumberRef.current - (piece.createdAtTurn || 0) < 2) {
        logEntry('⚠️ Doble Galope bloqueado: Jinete recién creado/promocionado');
        return;
      }
      setActiveAbility('jinete');
      setPendingJinete({ pieceId: piece.id, phase: 'first' });
    } else if (type === 'infante') {
      // Solución B: Coronación Anticipada disponible al llegar a la mitad de la cancha (o más allá).
      // El tablero tiene 9 filas (0-8); la fila central es la 4.
      // Dorado (gold) avanza hacia r=0 → habilitado en filas 0-4 (mitad enemiga + centro).
      // Carmesí (crimson) avanza hacia r=8 → habilitado en filas 4-8 (mitad enemiga + centro).
      // FIX: antes se excluía la fila central (4), por eso un Infante que llegaba
      // justo a la mitad no se podía coronar. Ahora alcanzar el centro ya habilita.
      const inEnemyHalf = (piece.color === 'gold' && piece.row <= 4) ||
                          (piece.color === 'crimson' && piece.row >= 4);
      if (!inEnemyHalf) {
        logEntry('⚠️ Coronación bloqueada: el Infante debe llegar al menos a la mitad de la cancha');
        return;
      }
      setActiveAbility('infante');
      setPromotionPick({ pieceId: piece.id });
    }
  }

  function executePlayerAbility(tr, tc) {
    ensureAudio();
    if (!selectedPiece) return;
    const piece = selectedPiece;
    const type = piece.type;
    const meEmoji = myColor === 'gold' ? '🟡' : '🔴';

    if (type === 'monarca') {
      setOncePerGame(prev => ({ ...prev, [myColor]: { ...prev[myColor], monarca: true }}));
      executeMove(piece.id, tr, tc, true, 'Salto Real');
    } else if (type === 'hechicera') {
      const targetP = piecesRef.current.find(p => !p.captured && p.row === tr && p.col === tc);
      // SAFETY: no permitir auto-captura ni capturar al Monarca con el Hechizo Letal
      // (defensa contra bug de targeting + NERF de la Hechicera)
      if (!targetP || targetP.color === myColor || targetP.type === 'monarca') return;
      playAbility('hechicera');
      setAnimating(true);
      const newPieces = piecesRef.current.map(p =>
        p.id === targetP.id ? { ...p, captured: true } : p
      );
      setPieces(newPieces); piecesRef.current = newPieces;
      sendIfLocal({ kind: 'spell', abilityKey: 'hechicera', attackerId: piece.id, victimId: targetP.id, cooldownVal: 7, abilityLabel: 'Hechizo Letal' });
      setCaptured(prev => ({ ...prev, [oppColor]: [...prev[oppColor], targetP.type] }));
      setCooldowns(prev => ({ ...prev, [myColor]: { ...prev[myColor], hechicera: 7 }}));
      logEntry(`${meEmoji} ⚜ Hechizo Letal ✕ ${PIECE_DATA[targetP.type].name}`);
      const isKing = targetP.type === 'monarca';
      setTimeout(() => isKing ? playKingCapture() : playRegularCapture(), 250);
      setTimeout(() => {
        setAnimating(false);
        const w = checkWinAfterMove(newPieces);
        if (w) { setWinner(w); setTimeout(() => { if (w===myColor) playVictory(); else playDefeat(); }, isKing ? 1500 : 200); return; }
        endTurn(myColor);
      }, ANIM_MS);
      setSelectedId(null); setHighlights([]); setAbilityTargets([]); setActiveAbility(null);
    } else if (type === 'fortaleza') {
      const targetP = piecesRef.current.find(p => !p.captured && p.row === tr && p.col === tc);
      // SAFETY: no permitir auto-captura (defensa contra bug de targeting)
      if (!targetP || targetP.color === myColor) return;
      playAbility('fortaleza');
      setAnimating(true);
      const newPieces = piecesRef.current.map(p =>
        p.id === targetP.id ? { ...p, captured: true } : p
      );
      setPieces(newPieces); piecesRef.current = newPieces;
      sendIfLocal({ kind: 'spell', abilityKey: 'fortaleza', attackerId: piece.id, victimId: targetP.id, cooldownVal: 6, abilityLabel: 'Aplastar' });
      setCaptured(prev => ({ ...prev, [oppColor]: [...prev[oppColor], targetP.type] }));
      setCooldowns(prev => ({ ...prev, [myColor]: { ...prev[myColor], fortaleza: 6 }}));
      logEntry(`${meEmoji} ⚜ Aplastar ✕ ${PIECE_DATA[targetP.type].name}`);
      const isKing = targetP.type === 'monarca';
      setTimeout(() => isKing ? playKingCapture() : playRegularCapture(), 250);
      setTimeout(() => {
        setAnimating(false);
        const w = checkWinAfterMove(newPieces);
        if (w) { setWinner(w); setTimeout(() => { if (w===myColor) playVictory(); else playDefeat(); }, isKing ? 1500 : 200); return; }
        endTurn(myColor);
      }, ANIM_MS);
      setSelectedId(null); setHighlights([]); setAbilityTargets([]); setActiveAbility(null);
    } else if (type === 'druida') {
      playAbility('druida');
      const newId = `spawn-${myColor}-${pieceIdCounter++}`;
      const newPieces = [...piecesRef.current, {
        id: newId, type: 'infante', color: myColor, row: tr, col: tc, captured: false,
        createdAtTurn: turnNumberRef.current
      }];
      setPieces(newPieces); piecesRef.current = newPieces;
      sendIfLocal({ kind: 'brote', spawnId: newId, color: myColor, row: tr, col: tc });
      setCooldowns(prev => ({ ...prev, [myColor]: { ...prev[myColor], druida: 9 }}));
      logEntry(`${meEmoji} ⚜ Brote → Infante en ${String.fromCharCode(97+tc)}${BOARD_SIZE-tr}`);
      setSelectedId(null); setHighlights([]); setAbilityTargets([]); setActiveAbility(null);
      setAnimating(true);
      setTimeout(() => { setAnimating(false); endTurn(myColor); }, 600);
    } else if (type === 'caballero') {
      setCooldowns(prev => ({ ...prev, [myColor]: { ...prev[myColor], caballero: 6 }}));
      executeMove(piece.id, tr, tc, true, 'Embestida');
    }
  }

  function applyPromotion(newType) {
    if (!promotionPick) return;
    playAbility('infante');
    const newPieces = piecesRef.current.map(p =>
      p.id === promotionPick.pieceId ? { ...p, type: newType, createdAtTurn: turnNumberRef.current } : p
    );
    setPieces(newPieces); piecesRef.current = newPieces;
    sendIfLocal({ kind: 'promote', pieceId: promotionPick.pieceId, newType });
    setOncePerGame(prev => ({ ...prev, [myColor]: { ...prev[myColor], infante: true }}));
    logEntry(`${myColor === 'gold' ? '🟡' : '🔴'} ⚜ Coronación → ${PIECE_DATA[newType].name}`);
    setPromotionPick(null);
    setSelectedId(null); setHighlights([]); setActiveAbility(null);
    setAnimating(true);
    setTimeout(() => { setAnimating(false); endTurn(myColor); }, 900);
  }

  // === MULTIPLAYER: aplicar acciones recibidas del rival ===
  function applyRemoteAction(action) {
    if (!action || !action.kind) return;

    // v11: el SERVIDOR ya validó que esta acción corresponde al turno del rival.
    // Si llegó hasta acá, es legítima. Ya NO la descartamos por mismatch de turno
    // local (eso era justamente lo que congelaba a un jugador para siempre).
    //
    // Solo hacemos deduplicación: si el server reenviara un duplicado exacto
    // (mismo _tn de una acción que cierra turno), lo ignoramos. Las sub-fases que
    // NO cierran turno (1er Doble Galope: turnEnds===false) NO se deduplican por
    // _tn porque comparten número con la fase siguiente.
    const closesTurn = action.turnEnds !== false;
    if (closesTurn && typeof action._tn === 'number') {
      if (action._tn === lastRemoteTnRef.current) {
        console.warn('[mp] duplicado ignorado _tn=', action._tn, action.kind);
        return;
      }
      lastRemoteTnRef.current = action._tn;
    }

    switch (action.kind) {
      case 'move': {
        // Si es la primera fase de Doble Galope, marcar pendingJinete antes de mover
        if (action.galopePhase === 'first') {
          setPendingJinete({ pieceId: action.pieceId, phase: 'first' });
        }
        executeMove(
          action.pieceId, action.toRow, action.toCol,
          !!action.isAbility, action.abilityLabel || null
        );
        // Si fue Embestida o Salto Real, setear cooldown / once-per-game del rival
        if (action.abilityLabel === 'Embestida') {
          setCooldowns(prev => ({ ...prev, [oppColor]: { ...prev[oppColor], caballero: 6 }}));
        } else if (action.abilityLabel === 'Salto Real') {
          setOncePerGame(prev => ({ ...prev, [oppColor]: { ...prev[oppColor], monarca: true }}));
        } else if (action.abilityLabel === 'Doble Galope (1°)') {
          setCooldowns(prev => ({ ...prev, [oppColor]: { ...prev[oppColor], jinete: 9 }}));
        }
        break;
      }
      case 'galope_pass': {
        setPendingJinete(null);
        logEntry(`${oppColor === 'gold' ? '🟡' : '🔴'} Jinete pasa su 2° galope`);
        setSelectedId(null); setHighlights([]);
        endTurn(oppColor);
        break;
      }
      case 'spell': {
        // Hechizo Letal / Aplastar — captura sin moverse.
        // El sonido va por la metadata (abilityKey), NO por buscar la pieza,
        // así suena SIEMPRE (antes, si no encontraba la pieza, descartaba todo
        // y no sonaba — ej. la Hechicera promovida que quedaba desincronizada).
        playAbility(action.abilityKey);
        const victim = piecesRef.current.find(p => p.id === action.victimId);
        setAnimating(true);
        if (victim) {
          const newPieces = piecesRef.current.map(p =>
            p.id === victim.id ? { ...p, captured: true } : p
          );
          setPieces(newPieces); piecesRef.current = newPieces;
          setCaptured(prev => ({ ...prev, [myColor]: [...prev[myColor], victim.type] }));
          const coord = `${String.fromCharCode(97+victim.col)}${BOARD_SIZE-victim.row}`;
          logEntry(`${oppColor === 'gold' ? '🟡' : '🔴'} ⚜ ${action.abilityLabel} ✕ ${PIECE_DATA[victim.type].name} en ${coord}`);
        } else {
          logEntry(`${oppColor === 'gold' ? '🟡' : '🔴'} ⚜ ${action.abilityLabel}`);
        }
        setCooldowns(prev => ({ ...prev, [oppColor]: { ...prev[oppColor], [action.abilityKey]: action.cooldownVal }}));
        const isKing = !!victim && victim.type === 'monarca';
        setTimeout(() => isKing ? playKingCapture() : playRegularCapture(), 250);
        setTimeout(() => {
          setAnimating(false);
          const w = checkWinAfterMove(piecesRef.current);
          if (w) { setWinner(w); setTimeout(() => { if (w===myColor) playVictory(); else playDefeat(); }, isKing ? 1500 : 200); return; }
          endTurn(oppColor);
        }, ANIM_MS);
        break;
      }
      case 'brote': {
        playAbility('druida');
        const newPieces = [...piecesRef.current, {
          id: action.spawnId, type: 'infante', color: action.color, row: action.row, col: action.col,
          captured: false, createdAtTurn: turnNumberRef.current
        }];
        setPieces(newPieces); piecesRef.current = newPieces;
        setCooldowns(prev => ({ ...prev, [oppColor]: { ...prev[oppColor], druida: 9 }}));
        logEntry(`${oppColor === 'gold' ? '🟡' : '🔴'} ⚜ Brote → Infante en ${String.fromCharCode(97+action.col)}${BOARD_SIZE-action.row}`);
        setAnimating(true);
        setTimeout(() => { setAnimating(false); endTurn(oppColor); }, 600);
        break;
      }
      case 'promote': {
        playAbility('infante');
        const newPieces = piecesRef.current.map(p =>
          p.id === action.pieceId ? { ...p, type: action.newType, createdAtTurn: turnNumberRef.current } : p
        );
        setPieces(newPieces); piecesRef.current = newPieces;
        setOncePerGame(prev => ({ ...prev, [oppColor]: { ...prev[oppColor], infante: true }}));
        logEntry(`${oppColor === 'gold' ? '🟡' : '🔴'} ⚜ Coronación → ${PIECE_DATA[action.newType].name}`);
        setAnimating(true);
        setTimeout(() => { setAnimating(false); endTurn(oppColor); }, 900);
        break;
      }
      default: break;
    }

    // ===== ANTI-DESYNC (verdad absoluta) =====
    // El que movió mandó su tablero completo. Lo copiamos EXACTO. Esto corrige
    // cualquier diferencia entre los dos teléfonos (promociones, conversiones,
    // capturas, brote, etc.) y elimina las piezas encimadas/congeladas, sin
    // importar el detalle de la acción. Es la red de seguridad del online.
    if (Array.isArray(action.pieces)) {
      const snap = action.pieces.map(p => ({ ...p }));
      setPieces(snap);
      piecesRef.current = snap;
    }
  }

  // Registrar handler de remote moves
  const applyRemoteRef = useRef(applyRemoteAction);
  useEffect(() => { applyRemoteRef.current = applyRemoteAction; });
  useEffect(() => {
    if (!multiplayer || !multiplayer.setRemoteHandler) return;
    multiplayer.setRemoteHandler((action) => applyRemoteRef.current(action));
    // Si el servidor rechaza una acción nuestra (llegó fuera de turno), limpiamos
    // cualquier selección/animación pendiente. El turno correcto ya viene en
    // serverTurn y el efecto de sincronización lo aplica.
    if (multiplayer.setRejectHandler) {
      multiplayer.setRejectHandler(() => {
        setSelectedId(null); setHighlights([]);
        setActiveAbility(null); setAbilityTargets([]);
        setPendingJinete(null);
      });
    }
    return () => {
      multiplayer.setRemoteHandler(() => {});
      if (multiplayer.setRejectHandler) multiplayer.setRejectHandler(() => {});
    };
  }, [multiplayer]);

  // v11: al volver de background (o cada tanto), pedir el estado de turno
  // autoritativo al servidor para resincronizar por las dudas.
  useEffect(() => {
    if (!multiplayer || !multiplayer.requestTurnState) return;
    function onVis() {
      if (document.visibilityState === 'visible') {
        try { multiplayer.requestTurnState(); } catch (_) {}
      }
    }
    document.addEventListener('visibilitychange', onVis);
    return () => document.removeEventListener('visibilitychange', onVis);
  }, [multiplayer]);

  const boardSize = cellSize * BOARD_SIZE;
  const visiblePieces = pieces.filter(p => !p.captured);

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>
      {/* Multiplayer header */}
      {multiplayer && (
        <div style={{
          background: COLORS.card, borderRadius: 10, padding: '10px 12px',
          border: `1px solid ${COLORS.goldDeep}66`,
        }}>
          <div style={{
            fontSize: 10, letterSpacing: 1.5, color: COLORS.gold,
            fontFamily: 'Cinzel, serif', fontWeight: 600, marginBottom: 4,
          }}>PARTIDA ONLINE</div>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: 8, fontSize: 12 }}>
            <div>
              <span style={{ color: COLORS.inkMute }}>Vos: </span>
              <span style={{ color: myColor === 'gold' ? COLORS.gold : COLORS.crimson, fontWeight: 600 }}>
                {myColor === 'gold' ? '🟡 Dorado' : '🔴 Carmesí'}
              </span>
            </div>
            <div>
              <span style={{ color: COLORS.inkMute }}>Rival: </span>
              <span style={{ color: COLORS.ink, fontWeight: 600 }}>{multiplayer.game.opponentName}</span>
            </div>
            {multiplayer.leaveGame && (
              <button onClick={multiplayer.leaveGame} style={{
                background: 'transparent', color: COLORS.crimson,
                border: `1px solid ${COLORS.crimson}88`,
                fontFamily: 'Cinzel, serif', fontSize: 10, letterSpacing: 1,
                padding: '4px 10px', borderRadius: 4, cursor: 'pointer',
              }}>SALIR</button>
            )}
          </div>
          {/* Indicador de turno (v11): siempre claro de quién es el turno */}
          {!winner && (
            <div style={{
              marginTop: 8, padding: '6px 10px', borderRadius: 6, textAlign: 'center',
              fontFamily: 'Cinzel, serif', fontSize: 12, letterSpacing: 1, fontWeight: 600,
              background: turn === myColor ? COLORS.gold : COLORS.cardLight,
              color: turn === myColor ? '#1A1410' : COLORS.inkMute,
              border: `1px solid ${turn === myColor ? COLORS.gold : COLORS.goldDeep + '44'}`,
            }}>
              {turn === myColor ? '➤ ES TU TURNO' : `Esperando a ${multiplayer.game.opponentName}…`}
            </div>
          )}
        </div>
      )}

      {/* Difficulty selector (solo en modo IA) */}
      {!multiplayer && (() => {
        // La dificultad se bloquea apenas ARRANCA la partida (al apretar
        // "COMENZAR PARTIDA"), o si ya se hizo algún movimiento. Para cambiarla
        // hay que REINICIAR y elegir antes de empezar.
        const difficultyLocked = started || turnNumber > 0;
        return (
        <div style={{
          background: COLORS.card, borderRadius: 10, padding: '10px 12px',
          border: `1px solid ${COLORS.goldDeep}66`,
        }}>
          <div style={{
            fontSize: 10, letterSpacing: 1.5, color: COLORS.gold,
            fontFamily: 'Cinzel, serif', fontWeight: 600, marginBottom: 6,
            display: 'flex', justifyContent: 'space-between', alignItems: 'center',
          }}>
            <span>DIFICULTAD</span>
            {difficultyLocked && (
              <span style={{ fontSize: 9, color: COLORS.inkMute, letterSpacing: 0.5, fontWeight: 400 }}>
                🔒 Reiniciá para cambiar
              </span>
            )}
          </div>
          <div style={{ display: 'flex', gap: 4, flexWrap: 'wrap' }}>
            {Object.entries(DIFFICULTY_LEVELS).map(([key, cfg]) => {
              const isSel = difficulty === key;
              return (
              <button
                key={key}
                disabled={difficultyLocked}
                onClick={() => { if (!difficultyLocked) setDifficulty(key); }}
                style={{
                  flex: '1 1 auto', minWidth: 80,
                  background: isSel ? COLORS.gold : 'transparent',
                  color: isSel ? '#1A1410' : COLORS.ink,
                  border: `1px solid ${isSel ? COLORS.gold : COLORS.goldDeep + '88'}`,
                  borderRadius: 4, padding: '6px 8px',
                  fontFamily: 'Cinzel, serif', fontWeight: 600,
                  fontSize: 11, letterSpacing: 1,
                  cursor: difficultyLocked ? 'not-allowed' : 'pointer',
                  opacity: difficultyLocked && !isSel ? 0.4 : 1,
                  transition: 'all 0.15s',
                }}>{cfg.label}</button>
              );
            })}
          </div>
        </div>
        );
      })()}

      {/* Scenario selector */}
      <div style={{
        background: COLORS.card, borderRadius: 10, padding: '10px 12px',
        border: `1px solid ${COLORS.goldDeep}66`,
      }}>
        <div style={{
          fontSize: 10, letterSpacing: 1.5, color: COLORS.gold,
          fontFamily: 'Cinzel, serif', fontWeight: 600, marginBottom: 6,
        }}>ESCENARIO</div>
        <div style={{ display: 'flex', gap: 4 }}>
          {Object.entries(SCENARIOS).map(([key, scn]) => (
            <button key={key} onClick={() => setScenario(key)} style={{
              flex: 1,
              background: scenario === key ? COLORS.gold : 'transparent',
              color: scenario === key ? '#1A1410' : COLORS.ink,
              border: `1px solid ${scenario === key ? COLORS.gold : COLORS.goldDeep + '88'}`,
              borderRadius: 4, padding: '6px 8px',
              fontFamily: 'Cinzel, serif', fontWeight: 600,
              fontSize: 11, letterSpacing: 1, cursor: 'pointer',
              transition: 'all 0.15s',
            }}>{scn.label}</button>
          ))}
        </div>
      </div>

      {/* Sonido toggles */}
      <div style={{
        background: COLORS.card, borderRadius: 10, padding: '10px 12px',
        border: `1px solid ${COLORS.goldDeep}66`,
      }}>
        <div style={{
          fontSize: 10, letterSpacing: 1.5, color: COLORS.gold,
          fontFamily: 'Cinzel, serif', fontWeight: 600, marginBottom: 8,
        }}>SONIDO</div>
        <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
          <SoundToggleRow
            label="Música ambiente"
            description="Melodía suave de fondo durante la partida"
            icon="🎵"
            checked={ambientOn}
            onChange={async (v) => {
              await ensureAudio();
              setAmbientOn(v);
            }}
          />
          <SoundToggleRow
            label="Sonidos de piezas"
            description="Movimientos, capturas y habilidades"
            icon="⚔️"
            checked={sfxOn}
            onChange={(v) => setSfxOn(v)}
          />
        </div>
      </div>

      {/* Status */}
      <div style={{
        background: COLORS.card, borderRadius: 10, padding: '10px 14px',
        border: `1px solid ${COLORS.goldDeep}66`,
        display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: 8,
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
          <div style={{
            width: 12, height: 12, borderRadius: '50%',
            background: turn === 'gold' ? COLORS.gold : COLORS.crimson,
            boxShadow: `0 0 8px ${turn === 'gold' ? COLORS.gold : COLORS.crimson}`,
            animation: aiThinking ? 'pulse 1s ease-in-out infinite' : 'none',
          }}/>
          <div style={{ fontFamily: 'Cinzel, serif', letterSpacing: 1.5, color: COLORS.ink, fontWeight: 600, fontSize: 13 }}>
            {winner ? (winner === myColor ? 'VICTORIA' : 'DERROTA') :
              aiThinking ? 'CARMESÍ PIENSA…' :
              animating ? '...' :
              multiplayer
                ? (turn === myColor ? 'TU TURNO' : `TURNO DE ${multiplayer.game.opponentName.toUpperCase()}`)
                : (turn === 'gold' ? 'TU TURNO' : 'TURNO CARMESÍ')}
          </div>
        </div>
        {multiplayer ? (
          <button onClick={() => multiplayer.leaveGame && multiplayer.leaveGame()} style={{
            background: 'transparent', color: COLORS.crimson,
            border: `1px solid ${COLORS.crimson}88`,
            fontFamily: 'Cinzel, serif', fontSize: 11, letterSpacing: 1,
            padding: '5px 12px', borderRadius: 4, cursor: 'pointer',
          }}>ABANDONAR</button>
        ) : (
          <button onClick={reset} style={{
            background: 'transparent', color: COLORS.gold,
            border: `1px solid ${COLORS.gold}`,
            fontFamily: 'Cinzel, serif', fontSize: 11, letterSpacing: 1,
            padding: '5px 12px', borderRadius: 4, cursor: 'pointer',
          }}>REINICIAR</button>
        )}
      </div>

      {/* Temporalizadores: reloj por jugador + total */}
      <div style={{
        background: COLORS.card, borderRadius: 10, padding: '10px 12px',
        border: `1px solid ${COLORS.goldDeep}66`,
      }}>
        <div style={{ display: 'flex', gap: 8 }}>
          {['gold', 'crimson'].map(col => {
            const active = started && !winner && turn === col;
            const isGold = col === 'gold';
            const accent = isGold ? COLORS.gold : COLORS.crimson;
            return (
              <div key={col} style={{
                flex: 1,
                background: active ? `${accent}22` : COLORS.bg,
                border: `1px solid ${active ? accent : COLORS.goldDeep + '44'}`,
                borderRadius: 8, padding: '8px 10px',
                boxShadow: active ? `0 0 10px ${accent}55` : 'none',
                transition: 'all 0.2s',
              }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 2 }}>
                  <div style={{
                    width: 9, height: 9, borderRadius: '50%', background: accent,
                    boxShadow: active ? `0 0 6px ${accent}` : 'none',
                    animation: active ? 'pulse 1.1s ease-in-out infinite' : 'none',
                  }}/>
                  <span style={{ fontFamily: 'Cinzel, serif', fontSize: 10, letterSpacing: 1.2, color: accent, fontWeight: 600 }}>
                    {isGold ? 'DORADO' : 'CARMESÍ'}{multiplayer && myColor === col ? ' (VOS)' : ''}
                  </span>
                </div>
                <div style={{ fontFamily: 'monospace', fontSize: 22, fontWeight: 700, color: COLORS.ink, letterSpacing: 1 }}>
                  {formatClock(clockDisplay[col])}
                </div>
              </div>
            );
          })}
        </div>
        <div style={{
          marginTop: 8, display: 'flex', justifyContent: 'center', alignItems: 'center', gap: 8,
          borderTop: `1px solid ${COLORS.goldDeep}33`, paddingTop: 8,
        }}>
          <span style={{ fontFamily: 'Cinzel, serif', fontSize: 10, letterSpacing: 1.5, color: COLORS.inkMute }}>⏱ TOTAL</span>
          <span style={{ fontFamily: 'monospace', fontSize: 16, fontWeight: 700, color: COLORS.gold, letterSpacing: 1 }}>
            {formatClock(clockDisplay.total)}
          </span>
        </div>
      </div>

      {/* Promotion modal */}
      {promotionPick && (
        <div style={{
          background: COLORS.card, borderRadius: 10, padding: 14,
          border: `2px solid ${COLORS.gold}`,
        }}>
          <div style={{
            fontFamily: 'Cinzel, serif', color: COLORS.gold, fontWeight: 600,
            marginBottom: 10, letterSpacing: 1.5, fontSize: 13,
          }}>⚜ CORONACIÓN — Elegí pieza:</div>
          <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap' }}>
            {['hechicera','caballero','fortaleza','jinete','druida'].map(t => (
              <button key={t} onClick={() => applyPromotion(t)} style={{
                background: COLORS.cardLight, border: `1px solid ${COLORS.goldDeep}`,
                padding: '6px 10px', borderRadius: 6, cursor: 'pointer',
                display: 'flex', alignItems: 'center', gap: 6, color: COLORS.ink,
                fontFamily: 'Cinzel, serif', fontSize: 12,
              }}>
                <PieceImage piece={{type: t, color: myColor}} size={28} />
                {PIECE_DATA[t].name}
              </button>
            ))}
          </div>
          <button onClick={() => { setPromotionPick(null); setActiveAbility(null); setSelectedId(null); }} style={{
            marginTop: 10, background: 'transparent', color: COLORS.inkMute,
            border: `1px solid ${COLORS.inkMute}66`, padding: '4px 12px',
            borderRadius: 4, fontSize: 11, cursor: 'pointer',
          }}>Cancelar</button>
        </div>
      )}

      {/* Botón COMENZAR PARTIDA (solo vs IA y antes de empezar) */}
      {!multiplayer && !started && (
        <div style={{ display: 'flex', justifyContent: 'center', marginBottom: 4 }}>
          <button onClick={startMatch} style={{
            width: '100%', maxWidth: 420, padding: '14px 18px',
            background: `linear-gradient(135deg, ${COLORS.goldBright} 0%, ${COLORS.gold} 50%, ${COLORS.goldDeep} 100%)`,
            color: '#1A1410', border: `2px solid ${COLORS.goldBright}`,
            borderRadius: 10, cursor: 'pointer',
            fontFamily: 'Cinzel, serif', fontWeight: 700, letterSpacing: 2, fontSize: 16,
            boxShadow: `0 4px 16px ${COLORS.goldDeep}88`,
            display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 10,
          }}>
            ⚔️ COMENZAR PARTIDA
          </button>
        </div>
      )}

      {/* Board */}
      <div style={{ display: 'flex', justifyContent: 'center' }}>
        <div style={{
          padding: 10,
          background: sc.frameBg,
          borderRadius: 8,
          border: `3px solid ${sc.frameBorder}`,
          boxShadow: `0 8px 24px rgba(0,0,0,0.5), inset 0 0 0 1px ${COLORS.gold}44`,
        }}>
          <div style={{
            position: 'relative', width: boardSize, height: boardSize, background: '#000',
          }}>
            {/* Cartel de inicio "¡A LAS ARMAS!" (estilo juego de pelea) */}
            {goAnim && (
              <div style={{
                position: 'absolute', inset: 0, zIndex: 50,
                display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
                pointerEvents: 'none',
                background: 'radial-gradient(circle at center, rgba(0,0,0,0.35) 0%, rgba(0,0,0,0) 70%)',
              }}>
                <div style={{
                  fontFamily: 'Cinzel, serif', fontWeight: 700,
                  fontSize: Math.max(28, Math.floor(boardSize / 9)),
                  letterSpacing: 3, color: COLORS.goldBright,
                  textShadow: `0 0 18px ${COLORS.gold}, 0 3px 6px #000, 0 0 40px ${COLORS.crimson}`,
                  animation: 'realezaGo 1.5s ease-out forwards',
                  textAlign: 'center', lineHeight: 1.1,
                }}>
                  ¡A LAS ARMAS!
                </div>
              </div>
            )}
            <div style={{
              display: 'grid',
              gridTemplateColumns: `repeat(${BOARD_SIZE}, ${cellSize}px)`,
              gridTemplateRows: `repeat(${BOARD_SIZE}, ${cellSize}px)`,
              position: 'absolute', inset: 0,
            }}>
              {Array.from({length: BOARD_SIZE*BOARD_SIZE}, (_, i) => {
                // dr,dc = posición VISUAL en el grid; r,c = posición LÓGICA en el board
                const dr = Math.floor(i / BOARD_SIZE), dc = i % BOARD_SIZE;
                const r = flipR(dr), c = flipC(dc);
                const dark = (r+c) % 2 === 1;
                const isHL = highlights.some(([nr,nc]) => nr===r && nc===c);
                const isAbT = abilityTargets.some(([nr,nc]) => nr===r && nc===c);
                const pAtCell = board[r][c];
                const isSel = selectedPiece && selectedPiece.row === r && selectedPiece.col === c;
                const isCapture = isHL && pAtCell;
                let bg = dark ? sc.tileDark : sc.tileLight;
                if (isSel) bg = COLORS.tileSel;
                if (isAbT) bg = COLORS.tileCap;
                return (
                  <div key={i} onClick={() => onSquareClick(r, c)}
                    style={{
                      width: cellSize, height: cellSize,
                      background: bg, position: 'relative',
                      cursor: 'pointer', transition: 'background 0.15s',
                      boxShadow: 'inset 0 0 0 1px rgba(0,0,0,0.15)',
                    }}>
                    {isHL && !isCapture && !pAtCell && (
                      <div style={{
                        position: 'absolute', top: '50%', left: '50%',
                        transform: 'translate(-50%,-50%)',
                        width: cellSize*0.25, height: cellSize*0.25, borderRadius: '50%',
                        background: COLORS.tileHL, boxShadow: `0 0 8px ${COLORS.tileHL}`,
                      }}/>
                    )}
                    {isCapture && (
                      <div style={{
                        position: 'absolute', inset: 3,
                        border: `3px solid ${COLORS.tileCap}`, borderRadius: '50%',
                        boxShadow: `0 0 12px ${COLORS.tileCap}`,
                      }}/>
                    )}
                  </div>
                );
              })}
            </div>
            {visiblePieces.map(p => (
              <div key={p.id} style={{
                position: 'absolute',
                top: flipR(p.row) * cellSize, left: flipC(p.col) * cellSize,
                width: cellSize, height: cellSize,
                transition: `top ${ANIM_MS}ms cubic-bezier(0.4, 0.0, 0.2, 1), left ${ANIM_MS}ms cubic-bezier(0.4, 0.0, 0.2, 1)`,
                pointerEvents: 'none',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
              }}>
                <PieceImage piece={p} size={cellSize - 4} />
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Selected piece + ability */}
      {selectedPiece && selectedPiece.color === myColor && !winner && !pendingJinete && (
        <div style={{
          background: COLORS.card, borderRadius: 10, padding: 12,
          border: `1px solid ${COLORS.goldDeep}66`,
        }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 8 }}>
            <PieceImage piece={selectedPiece} size={40} />
            <div style={{ flex: 1 }}>
              <div style={{ fontFamily: 'Cinzel, serif', color: COLORS.ink, fontSize: 16, letterSpacing: 1.5, fontWeight: 600 }}>
                {PIECE_DATA[selectedPiece.type].name}
              </div>
              <div style={{ fontSize: 11, color: COLORS.inkMute, fontStyle: 'italic', lineHeight: 1.3 }}>
                {PIECE_DATA[selectedPiece.type].movement}
              </div>
            </div>
          </div>
          {/* Header sección habilidad especial */}
          <div style={{
            fontFamily: 'Cinzel, serif', fontSize: 10, letterSpacing: 2,
            color: COLORS.gold, marginTop: 4, marginBottom: 6,
            borderTop: `1px solid ${COLORS.goldDeep}44`, paddingTop: 8,
          }}>
            HABILIDAD ESPECIAL
          </div>
          <button
            onClick={activateAbility}
            disabled={!abilityAvailable(selectedPiece.type)}
            style={{
              width: '100%', padding: '8px 10px',
              background: abilityAvailable(selectedPiece.type) ? COLORS.gold : COLORS.cardLight,
              color: abilityAvailable(selectedPiece.type) ? '#1A1410' : COLORS.inkMute,
              border: 'none', borderRadius: 6,
              fontFamily: 'Cinzel, serif', fontWeight: 600, letterSpacing: 1.2,
              cursor: abilityAvailable(selectedPiece.type) ? 'pointer' : 'not-allowed',
              fontSize: 12, textAlign: 'left',
              display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: 8,
            }}>
            <span>⚜ {PIECE_DATA[selectedPiece.type].abilityName}</span>
            <span style={{ fontSize: 10, opacity: 0.7 }}>
              {!abilityAvailable(selectedPiece.type) ?
                ((selectedPiece.type === 'monarca' || selectedPiece.type === 'infante') ?
                  'USADA' : `${cooldowns[myColor][selectedPiece.type]}T`) :
                'DISPONIBLE'}
            </span>
          </button>
          <div style={{ fontSize: 11, color: COLORS.inkMute, marginTop: 6, lineHeight: 1.4 }}>
            {PIECE_DATA[selectedPiece.type].abilityDesc}
          </div>
        </div>
      )}

      {pendingJinete && pendingJinete.phase === 'second' && !pendingJinete.aiMode && (
        <div style={{
          background: COLORS.gold, color: '#1A1410',
          padding: '8px 12px', borderRadius: 6,
          fontFamily: 'Cinzel, serif', fontSize: 12, letterSpacing: 1, textAlign: 'center', fontWeight: 600,
        }}>
          ⚜ DOBLE GALOPE — Hacé el 2° movimiento o tocá afuera para saltearlo
        </div>
      )}

      {/* Captures */}
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10 }}>
        <div style={{
          background: COLORS.card, borderRadius: 8, padding: 8,
          border: `1px solid ${COLORS.goldDeep}66`,
        }}>
          <div style={{ fontFamily: 'Cinzel, serif', fontSize: 9, letterSpacing: 1.5, color: COLORS.gold, marginBottom: 4 }}>
            CAPTURADAS POR DORADO
          </div>
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: 3, minHeight: 22 }}>
            {captured.crimson.map((t, i) => (
              <PieceImage key={i} piece={{type: t, color: 'crimson'}} size={20} />
            ))}
          </div>
        </div>
        <div style={{
          background: COLORS.card, borderRadius: 8, padding: 8,
          border: `1px solid ${COLORS.crimsonDeep}66`,
        }}>
          <div style={{ fontFamily: 'Cinzel, serif', fontSize: 9, letterSpacing: 1.5, color: COLORS.crimson, marginBottom: 4 }}>
            CAPTURADAS POR CARMESÍ
          </div>
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: 3, minHeight: 22 }}>
            {captured.gold.map((t, i) => (
              <PieceImage key={i} piece={{type: t, color: 'gold'}} size={20} />
            ))}
          </div>
        </div>
      </div>

      {/* Log */}
      <div style={{
        background: COLORS.card, borderRadius: 8, padding: 10,
        border: `1px solid ${COLORS.goldDeep}66`,
        maxHeight: 140, overflowY: 'auto',
      }}>
        <div style={{ fontFamily: 'Cinzel, serif', fontSize: 9, letterSpacing: 1.5, color: COLORS.gold, marginBottom: 4 }}>
          REGISTRO
        </div>
        {log.length === 0 ? (
          <div style={{ fontSize: 11, color: COLORS.inkMute, fontStyle: 'italic' }}>Empezá tocando una pieza {myColor === 'gold' ? 'dorada' : 'carmesí'}.</div>
        ) : log.slice().reverse().map((l, i) => (
          <div key={i} style={{ fontSize: 11, color: COLORS.ink, fontFamily: 'monospace', lineHeight: 1.5 }}>{l}</div>
        ))}
      </div>

      {winner && (
        <div style={{
          background: winner === 'gold' ? COLORS.gold : COLORS.crimson,
          color: winner === 'gold' ? '#1A1410' : '#FFF5E8',
          padding: 16, borderRadius: 8,
          fontFamily: 'Cinzel, serif', fontSize: 18, letterSpacing: 2, fontWeight: 700,
          textAlign: 'center',
        }}>
          {winner === 'gold' ? '⚜ VICTORIA DORADA ⚜' : '⚜ VICTORIA CARMESÍ ⚜'}
        </div>
      )}
    </div>
  );
}

// ============== ROOT ==============

function Realeza() {
  const [tab, setTab] = useState('jugar');

  useEffect(() => {
    if (typeof document === 'undefined') return;
    if (!document.getElementById('cinzel-font')) {
      const link = document.createElement('link');
      link.id = 'cinzel-font'; link.rel = 'stylesheet';
      link.href = 'https://fonts.googleapis.com/css2?family=Cinzel:wght@400;600;700&display=swap';
      document.head.appendChild(link);
    }
    if (!document.getElementById('realeza-style')) {
      const style = document.createElement('style');
      style.id = 'realeza-style';
      style.textContent = `@keyframes pulse { 0%,100% { opacity: 1; } 50% { opacity: 0.4; } }
@keyframes realezaBurst { 0% { transform: translate(-50%,-50%) scale(0.2); opacity: 0.9; } 100% { transform: translate(-50%,-50%) scale(2.4); opacity: 0; } }
@keyframes realezaSprout { 0%,100% { box-shadow: 0 0 0 0 rgba(127,175,107,0.0); } 50% { box-shadow: 0 0 10px 3px rgba(127,175,107,0.7); } }
@keyframes realezaBolt { 0% { box-shadow: 0 0 4px 1px currentColor; } 50% { box-shadow: 0 0 12px 5px currentColor; } 100% { box-shadow: 0 0 4px 1px currentColor; } }
@keyframes realezaGo { 0% { transform: scale(0.2); opacity: 0; } 22% { transform: scale(1.18); opacity: 1; } 60% { transform: scale(1); opacity: 1; } 80% { transform: scale(1.04); opacity: 1; } 100% { transform: scale(1.5); opacity: 0; } }`;
      document.head.appendChild(style);
    }
  }, []);

  const TabBtn = ({ id, label }) => (
    <button onClick={() => setTab(id)} style={{
      flex: 1,
      background: tab === id ? COLORS.gold : 'transparent',
      color: tab === id ? '#1A1410' : COLORS.ink,
      border: `1px solid ${tab === id ? COLORS.gold : COLORS.goldDeep + '66'}`,
      fontFamily: 'Cinzel, serif', fontWeight: 600,
      fontSize: 13, letterSpacing: 1.5, padding: '10px 8px',
      cursor: 'pointer', transition: 'all 0.15s',
    }}>{label}</button>
  );

  return (
    <div style={{
      background: COLORS.bg, minHeight: '100vh', color: COLORS.ink,
      fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif',
      padding: 14,
    }}>
      <div style={{ maxWidth: 760, margin: '0 auto' }}>
        <header style={{ textAlign: 'center', marginBottom: 14, paddingTop: 4 }}>
          <div style={{
            fontFamily: 'Cinzel, serif', fontSize: 11, letterSpacing: 4,
            color: COLORS.gold, marginBottom: 2,
          }}>UN JUEGO DE 9×9</div>
          <h1 style={{
            fontFamily: 'Cinzel, serif', fontSize: 40, fontWeight: 700,
            letterSpacing: 8, color: COLORS.ink, margin: 0,
          }}>REALEZA</h1>
        </header>

        <div style={{ display: 'flex', gap: 4, marginBottom: 14 }}>
          <TabBtn id="jugar" label="JUGAR" />
          <TabBtn id="piezas" label="PIEZAS" />
          <TabBtn id="reglas" label="REGLAS" />
        </div>

        {tab === 'piezas' && <PiezasTab />}
        {tab === 'reglas' && <ReglasTab />}
        {tab === 'jugar' && <JugarTab />}

        <footer style={{
          marginTop: 20, paddingTop: 14,
          borderTop: `1px solid ${COLORS.goldDeep}33`,
          textAlign: 'center', fontSize: 10, color: COLORS.inkMute, letterSpacing: 1,
        }}>
          REALEZA · IA AVANZADA · MÚSICA AMBIENTE · ZOOM DE PIEZAS
        </footer>
      </div>
    </div>
  );
}

export default Realeza;
export { JugarTab };
